-- Adicionar coluna para Logo SVG nas plataformas
ALTER TABLE platforms ADD COLUMN logo_svg text;

-- Atualizar serviços para usar Emojis em vez de texto (resolvendo o problema da imagem 1)
UPDATE services SET icon = '🌍' WHERE icon = 'world';
UPDATE services SET icon = '🇧🇷' WHERE icon = 'br';
UPDATE services SET icon = '❤️' WHERE icon = 'heart';
UPDATE services SET icon = '👁️' WHERE icon = 'eye';
UPDATE services SET icon = '🎬' WHERE icon = 'play';

